function allObjectives(subjectKey){const d=window.__ibData||{},overrides=d.objectiveOverrides||{},archived=d.archivedObjectives||[];const base=staticObjectives(subjectKey).map(o=>Object.assign({},o,overrides[o.id]||{}));const custom=(d.customObjectives||[]).filter(o=>o.subject===subjectKey);return base.concat(custom).filter(o=>!archived.includes(o.id));}
