function loadData(){try{const saved=JSON.parse(localStorage.getItem(KEY));if(saved)return migrate(saved)}catch(e){}const progress={};Object.keys(SUBJECTS).forEach((key,si)=>staticObjectives(key).forEach((o,i)=>{progress[o.id]={school:i<(si===0?15:si===1?8:10),status:i<(si===0?5:si===1?4:3)?'done':i<(si===0?9:si===1?7:6)?'progress':'todo',confidence:i<(si===0?5:si===1?4:3)?4:i<(si===0?9:si===1?7:6)?2:0}}));return migrate({progress,practice:DEFAULT_PRACTICE});}
function save(){window.__ibData=data;localStorage.setItem(KEY,JSON.stringify(data));queueCloudSave()}
function setSyncStatus(text,state){const el=document.querySelector('#syncStatus');if(!el)return;el.className='sync-status '+(state||'');el.innerHTML='<i></i> '+text}
function queueCloudSave(){if(!cloudClient||!cloudUser||cloudLoading)return;clearTimeout(cloudSaveTimer);setSyncStatus('동기화 중…','syncing');cloudSaveTimer=setTimeout(syncToCloud,650)}
async function syncToCloud(){if(!cloudClient||!cloudUser)return;const result=activeWorkspace?await cloudClient.from('workspace_data').upsert({workspace_id:activeWorkspace.workspace_id,payload:data,updated_at:new Date().toISOString()}):await cloudClient.from('user_data').upsert({user_id:cloudUser.id,payload:data,updated_at:new Date().toISOString()});if(result.error){setSyncStatus('동기화 오류','error');console.error(result.error)}else setSyncStatus(activeWorkspace?'가족 Workspace 저장됨':'클라우드 저장됨','online')}
async function refreshWorkspace(){activeWorkspace=null;if(!cloudClient||!cloudUser)return;const result=await cloudClient.rpc('get_my_workspace');if(!result.error&&result.data&&result.data.length)activeWorkspace=result.data[0];renderWorkspace();renderSyllabus()}
async function loadCloudData(){if(!cloudClient||!cloudUser)return;cloudLoading=true;setSyncStatus('클라우드 확인 중…','syncing');const result=activeWorkspace?await cloudClient.from('workspace_data').select('payload').eq('workspace_id',activeWorkspace.workspace_id).maybeSingle():await cloudClient.from('user_data').select('payload').eq('user_id',cloudUser.id).maybeSingle();if(result.error){setSyncStatus(activeWorkspace?'Workspace 설정 필요':'DB 설정 필요','error');cloudLoading=false;return}if(result.data&&result.data.payload&&Object.keys(result.data.payload).length){data=migrate(result.data.payload);window.__ibData=data;localStorage.setItem(KEY,JSON.stringify(data));renderAll();setSyncStatus(activeWorkspace?'가족 Workspace 연결됨':'클라우드 연결됨','online')}else{cloudLoading=false;await syncToCloud();setSyncStatus('첫 데이터 업로드됨','online');return}cloudLoading=false}
async function handleSession(session){cloudUser=session&&session.user?session.user:null;const button=document.querySelector('#accountButton');if(cloudUser){button.textContent=cloudUser.email||'계정';await refreshWorkspace();await loadCloudData()}else{activeWorkspace=null;button.textContent='로그인';setSyncStatus('이 기기에 저장됨','');renderWorkspace();renderSyllabus()}}
async function initCloud(){const cfg=window.IB_SUPABASE_CONFIG;if(!cfg||!window.supabase){setSyncStatus('오프라인 모드','error');return}cloudClient=window.supabase.createClient(cfg.url,cfg.publishableKey);const sessionResult=await cloudClient.auth.getSession();await handleSession(sessionResult.data.session);cloudClient.auth.onAuthStateChange((event,session)=>{if(event==='SIGNED_IN'||event==='SIGNED_OUT')setTimeout(()=>handleSession(session),0)})}
function statusLabel(v){return {done:'✓ 완료',progress:'↻ 진행 중',todo:'○ 미완'}[v]}
function metrics(key){const list=allObjectives(key), states=list.map(o=>data.progress[o.id]||{}),done=states.filter(x=>x.status==='done').length,progress=states.filter(x=>x.status==='progress').length,gaps=list.filter(o=>isGap(o.id)).length;return{total:list.length,done,progress,gaps,pct:Math.round(done/list.length*100)}}
function isGap(id){const p=data.progress[id]||{};return p.school&&(p.status!=='done'||(+p.confidence||0)<3)}
function gapItems(){return Object.keys(SUBJECTS).flatMap(k=>allObjectives(k).filter(o=>isGap(o.id)).map(o=>({...o,subject:k})));}
function renderAll(){renderDashboard();renderSyllabus();renderLearningObjectives();renderPractice();renderFlashcards();renderFocus();}
