function renderSyllabus(){renderTabs();const searchEl=document.querySelector('#searchInput'),filterEl=document.querySelector('#statusFilter'),q=searchEl?searchEl.value.toLowerCase():'',filter=filterEl?filterEl.value:'all',m=metrics(selectedSubject),canManage=!activeWorkspace||activeWorkspace.member_role==='owner';document.querySelector('#addObjective').classList.toggle('owner-only-hidden',!canManage);document.querySelector('#syllabusSummary').innerHTML=`<div class="summary-metric"><strong>${m.total}</strong><span>전체 항목</span></div><div class="summary-metric"><strong>${m.done}</strong><span>완료</span></div><div class="summary-metric"><strong>${m.progress}</strong><span>진행 중</span></div><div class="summary-metric"><strong>${m.gaps}</strong><span>Focus gaps</span></div><div class="summary-metric"><strong>${m.pct}%</strong><span>Mastery</span></div>`;
  const grouped={};allObjectives(selectedSubject).forEach(o=>{if(!grouped[o.group])grouped[o.group]=[];grouped[o.group].push(o)});document.querySelector('#syllabusList').innerHTML=Object.entries(grouped).map(([group,items])=>{const objs=items.filter(o=>{const p=data.progress[o.id]||{status:'todo'};return(!q||(o.code+' '+o.title+' '+o.category).toLowerCase().includes(q))&&(filter==='all'||filter==='gap'&&isGap(o.id)||p.status===filter)});if(!objs.length)return'';return `<section class="syllabus-group"><button class="group-header"><span>${group}</span><small>${objs.length} objectives</small><span class="chevron">⌄</span></button><div class="objective-list">${objs.map(o=>{const p=data.progress[o.id]||{school:false,status:'todo',confidence:0};return `<div class="objective"><code>${o.code}</code><div class="objective-title"><div><b>${o.title}</b><small>${o.category}</small></div>${canManage?`<button class="objective-edit" data-edit-objective="${o.id}" title="항목 편집">✎</button>`:''}</div><button class="school-toggle ${p.school?'taught':''}" data-school="${o.id}">${p.school?'✓ 학교 완료':'학교 미진도'}</button><select class="status-select" data-status="${o.id}"><option value="todo" ${p.status==='todo'?'selected':''}>○ 미완</option><option value="progress" ${p.status==='progress'?'selected':''}>↻ 진행 중</option><option value="done" ${p.status==='done'?'selected':''}>✓ 완료</option></select><select class="confidence-select" data-confidence="${o.id}" aria-label="자신감"><option value="0" ${!p.confidence?'selected':''}>자신감 —</option>${[1,2,3,4,5].map(n=>`<option value="${n}" ${+p.confidence===n?'selected':''}>${'★'.repeat(n)} ${n}</option>`).join('')}</select><span class="gap-dot ${isGap(o.id)?'active':''}" title="${isGap(o.id)?'복습 필요':'Gap 없음'}"></span></div>`}).join('')}</div></section>`}).join('')||'<div class="empty">조건에 맞는 syllabus 항목이 없습니다.</div>'}
function renderPractice(){const scores=data.practice.map(p=>+p.score).filter(Number.isFinite),avg=scores.length?Math.round(scores.reduce((a,b)=>a+b,0)/scores.length):0,atTarget=scores.filter(x=>x>=75).length,last=scores.length?scores[scores.length-1]:0;document.querySelector('#practiceStats').innerHTML=[['기록',data.practice.length,'#587b96'],['평균 점수',avg+'%','#bd6549'],['목표 달성',atTarget+'회','#d6a44f'],['최근 점수',last+'%','#204b40']].map(x=>`<div class="stat-card" style="--accent:${x[2]}"><strong>${x[1]}</strong><span>${x[0]}</span></div>`).join('');document.querySelector('#practiceTable').innerHTML=[...data.practice].reverse().map(p=>`<tr><td>${p.date}</td><td>${SUBJECTS[p.subject].name}</td><td><b>${p.name}</b></td><td>${p.topic||'—'}</td><td class="score-cell">${p.score}%</td><td>${p.notes||'—'}</td></tr>`).join('')}
function today(){return new Date().toISOString().slice(0,10)}
