  const filter=document.querySelector('#cardSubjectFilter').value;const cards=data.flashcards.filter(c=>filter==='all'||c.subject===filter);document.querySelector('#cardLibrary').innerHTML=cards.map(c=>`<div class="library-card ${c.id===currentCardId?'active':''}" data-card-id="${c.id}" role="button" tabindex="0"><span><b>${escapeHtml(c.front)}</b><small>${SUBJECTS[c.subject].short} · ${c.code||c.type} · <span class="${(c.due||today())<=today()?'due-pill':''}">${(c.due||today())<=today()?'오늘 복습':'다음 '+c.due}</span></small></span><button data-delete-card="${c.id}" title="카드 삭제">×</button></div>`).join('')||'<div class="empty">카드가 없습니다.</div>'
