function escapeHtml(value){return String(value||'').replace(/[&<>"']/g,ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]))}
function formatFlashcardAnswer(card){
  if(card&&card.id==='card-binomial-general-term')return `<div class="math-answer"><span class="math-label">General term</span><div class="math-formula"><span class="math-symbol">T<sub>r+1</sub></span><span>=</span><span class="binom"><span>n</span><span>r</span></span><span>a<sup>n-r</sup>b<sup>r</sup></span></div><div class="math-note">또는 <span class="math-symbol">T<sub>r+1</sub></span> = <span class="math-symbol">C(n,r)</span> · <span>a<sup>n-r</sup></span> · <span>b<sup>r</sup></span></div><div class="math-warning">주의: r번째 항이 아니라 <b>(r+1)번째 항</b>이다.</div></div>`;
  if(card&&card.id==='card-limit-xlnx-lhopital')return `<div class="math-answer"><span class="math-label">L’Hôpital setup</span><div class="math-formula"><span class="math-symbol">x ln x</span><span>=</span><span class="frac"><span>ln x</span><span>x<sup>-1</sup></span></span></div><div class="math-note">This becomes <b>−∞ / +∞</b>, so L’Hôpital applies.</div><div class="math-formula small"><span class="frac"><span>1/x</span><span>−1/x<sup>2</sup></span></span><span>=</span><span>−x</span><span>→</span><span>0</span></div><div class="math-warning">Ivan trap: <b>(1/x)/(−1/x²)</b> is not <b>1/0</b>. 복잡한 분수는 reciprocal로 곱해서 정리한다.</div></div>`;
  return escapeHtml(card&&card.back).replace(/\n/g,'<br>');
}
function nextInterval(card,rating){const current=card.interval||0;if(rating==='again')return 0;if(rating==='hard')return 1;if(rating==='easy')return current<1?4:Math.max(4,Math.round(current*2.5));return current<1?1:current<3?3:Math.round(current*2)}
function rateCard(rating){const card=data.flashcards.find(c=>c.id===currentCardId);if(!card)return;const days=nextInterval(card,rating);card.interval=days;card.reviews=(card.reviews||0)+1;const next=new Date();next.setDate(next.getDate()+days);card.due=next.toISOString().slice(0,10);answerVisible=false;currentCardId=null;save();renderAll();toast(days?'다음 복습: '+days+'일 후':'잠시 후 다시 보여드릴게요')}
