function showUpdateBanner(version){const el=document.querySelector('#updateBanner');if(!el)return;el.querySelector('span').textContent=`새 버전 v${version}이 준비되었습니다.`;el.classList.add('show')}
async function applyAppUpdate(){try{if('serviceWorker'in navigator){const regs=await navigator.serviceWorker.getRegistrations();await Promise.all(regs.map(r=>r.update()))}if(window.caches){const keys=await caches.keys();await Promise.all(keys.filter(k=>k.startsWith('ib-compass-')).map(k=>caches.delete(k)))}}catch(e){console.warn('Update refresh skipped cache cleanup',e)}location.replace(location.origin+location.pathname)}
async function checkForAppUpdate(){try{const res=await fetch(`version.json?t=${Date.now()}`,{cache:'no-store'});if(!res.ok)return;const info=await res.json();if(info.version&&String(info.version)!==APP_VERSION)showUpdateBanner(info.version)}catch(e){}}
function openDialog(){const f=document.querySelector('#practiceForm');f.reset();f.elements.date.value=new Date().toISOString().slice(0,10);document.querySelector('#practiceDialog').showModal()}
function openCardDialog(){document.querySelector('#flashcardForm').reset();document.querySelector('#flashcardDialog').showModal()}
function findObjective(id){return Object.keys(SUBJECTS).flatMap(k=>allObjectives(k)).find(o=>o.id===id)}
function renderWorkspace(){const current=document.querySelector('#workspaceCurrent'),setup=document.querySelector('#workspaceSetup');if(!current||!setup)return;if(!activeWorkspace){current.innerHTML='';setup.classList.remove('hidden');return}setup.classList.add('hidden');const owner=activeWorkspace.member_role==='owner';current.innerHTML=`<div class="workspace-info"><span class="role-chip">${owner?'Owner · 부모':'Student · Ivan'}</span><h3>${escapeHtml(activeWorkspace.workspace_name)}</h3><p>${owner?'Syllabus를 관리하고 학생을 초대할 수 있습니다.':'진도, Practice와 Flashcard가 가족 계정과 공유됩니다.'}</p>${owner?`<div class="invite-box"><span><small>IVAN 초대 코드</small><br><code>${activeWorkspace.invite_code}</code></span><button type="button" data-copy-invite>코드 복사</button></div>`:`<p class="student-note">Syllabus 구조 변경은 Owner 계정에서 관리합니다.</p>`}</div>`}
function openObjectiveDialog(id){if(activeWorkspace&&activeWorkspace.member_role!=='owner'){toast('Syllabus 편집은 Owner만 가능합니다');return}const f=document.querySelector('#objectiveForm');f.reset();const o=id?findObjective(id):null;f.elements.originalId.value=o?o.id:'';f.elements.subject.value=o?o.subject:selectedSubject;f.elements.subject.disabled=!!o;f.elements.code.value=o?o.code:'';f.elements.group.value=o?o.group:'';f.elements.title.value=o?o.title:'';f.elements.category.value=o?o.category:'';f.elements.level.value=o&&o.level?o.level:'SL + HL';document.querySelector('#objectiveDialogTitle').textContent=o?'항목 수정':'항목 추가';document.querySelector('#archiveObjective').classList.toggle('hidden',!o);document.querySelector('#objectiveDialog').showModal()}
document.addEventListener('click',e=>{
  const closeButton=e.target.closest('.close, button[value="cancel"]');if(closeButton){e.preventDefault();const dialog=closeButton.closest('dialog');if(dialog)dialog.close();return}
  const loButton=e.target.closest('[data-open-lo]');if(loButton){openLearningObjectiveDrawer(loButton.dataset.openLo);return}
  const learningRow=e.target.closest('.has-learning-detail');if(learningRow&&!e.target.closest('select,button')){const codeEl=learningRow.querySelector('code'),code=codeEl?codeEl.textContent.trim():'',o=allObjectives('math').find(item=>item.code===code);if(o)openLearningObjectiveDrawer(o.id);return}
  const view=e.target.closest('[data-view]');if(view)switchView(view.dataset.view);
  const go=e.target.closest('[data-go]');if(go)switchView(go.dataset.go);
  const subject=e.target.closest('[data-subject]');if(subject){selectedSubject=subject.dataset.subject;renderSyllabus();renderLearningObjectives()}
  const open=e.target.closest('[data-subject-open]');if(open){selectedSubject=open.dataset.subjectOpen;renderSyllabus();renderLearningObjectives();switchView('syllabus')}
  const school=e.target.closest('[data-school]');if(school){data.progress[school.dataset.school].school=!data.progress[school.dataset.school].school;save();renderAll();toast('학교 진도를 업데이트했습니다')}
  const header=e.target.closest('.group-header');if(header)header.parentElement.classList.toggle('collapsed');
  const complete=e.target.closest('[data-complete]');if(complete){data.progress[complete.dataset.complete].status='done';data.progress[complete.dataset.complete].confidence=Math.max(3,data.progress[complete.dataset.complete].confidence||0);save();renderAll();toast('완료로 표시했습니다')}
  const edit=e.target.closest('[data-edit-objective]');if(edit)openObjectiveDialog(edit.dataset.editObjective);
  if(e.target.closest('[data-new-card]'))openCardDialog();
  if(e.target.closest('[data-flip-card]')){answerVisible=true;renderFlashcards()}
  const libraryCard=e.target.closest('[data-card-id]');if(libraryCard&&!e.target.closest('button')){currentCardId=libraryCard.dataset.cardId;answerVisible=false;renderFlashcards();return}
  const rate=e.target.closest('[data-rate]');if(rate)rateCard(rate.dataset.rate);
  const removeCard=e.target.closest('[data-delete-card]');if(removeCard&&confirm('이 Flashcard를 삭제할까요?')){data.flashcards=data.flashcards.filter(c=>c.id!==removeCard.dataset.deleteCard);save();renderAll();toast('카드를 삭제했습니다')}
  if(e.target.closest('[data-copy-invite]')&&activeWorkspace){navigator.clipboard.writeText(activeWorkspace.invite_code);toast('초대 코드를 복사했습니다')}
});
document.addEventListener('change',e=>{if(e.target.matches('[data-status]')){const id=e.target.dataset.status;data.progress[id].status=e.target.value;if(e.target.value==='done'&&!data.progress[id].confidence)data.progress[id].confidence=3;save();renderAll();toast('학습 상태를 저장했습니다')}if(e.target.matches('[data-confidence]')){data.progress[e.target.dataset.confidence].confidence=+e.target.value;save();renderAll();toast('자신감을 저장했습니다')}});
document.querySelector('#searchInput').addEventListener('input',renderSyllabus);document.querySelector('#statusFilter').addEventListener('change',renderSyllabus);
document.querySelector('#quickAdd').addEventListener('click',openDialog);document.querySelector('#addPractice').addEventListener('click',openDialog);
document.querySelector('#addFlashcard').addEventListener('click',openCardDialog);document.querySelector('#addObjective').addEventListener('click',()=>openObjectiveDialog());
const updateNowButton=document.querySelector('#updateNow'),dismissUpdateButton=document.querySelector('#dismissUpdate');if(updateNowButton)updateNowButton.addEventListener('click',applyAppUpdate);if(dismissUpdateButton)dismissUpdateButton.addEventListener('click',()=>{const el=document.querySelector('#updateBanner');if(el)el.classList.remove('show')});
document.querySelector('#resetButton').addEventListener('click',()=>{if(confirm('저장된 변경사항을 지우고 샘플 상태로 되돌릴까요?')){localStorage.removeItem(KEY);data=loadData();save();renderAll();toast('샘플 데이터로 초기화했습니다')}});
const subjectSelect=document.querySelector('#practiceForm [name=subject]');subjectSelect.innerHTML=Object.entries(SUBJECTS).map(([k,s])=>`<option value="${k}">${s.name}</option>`).join('');
const subjectOptions=Object.entries(SUBJECTS).map(([k,s])=>`<option value="${k}">${s.name}</option>`).join('');document.querySelector('#flashcardForm [name=subject]').innerHTML=subjectOptions;document.querySelector('#objectiveForm [name=subject]').innerHTML=subjectOptions;document.querySelector('#cardSubjectFilter').innerHTML='<option value="all">모든 과목</option>'+subjectOptions;document.querySelector('#cardSubjectFilter').addEventListener('change',renderFlashcards);
document.querySelector('#savePractice').addEventListener('click',e=>{const f=document.querySelector('#practiceForm');if(!f.reportValidity()){e.preventDefault();return}const fd=new FormData(f);data.practice.push({date:fd.get('date'),subject:fd.get('subject'),name:fd.get('name'),topic:fd.get('topic'),score:+fd.get('score'),notes:fd.get('notes')});save();renderAll();toast('연습 기록을 저장했습니다')});
document.querySelector('#saveFlashcard').addEventListener('click',e=>{const f=document.querySelector('#flashcardForm');if(!f.reportValidity()){e.preventDefault();return}const fd=new FormData(f);data.flashcards.push({id:'card-'+Date.now(),subject:fd.get('subject'),code:fd.get('code'),type:fd.get('type'),tag:fd.get('tag'),front:fd.get('front'),back:fd.get('back'),due:today(),interval:0,reviews:0});currentCardId=null;save();renderAll();toast('Flashcard를 만들었습니다')});
document.querySelector('#saveObjective').addEventListener('click',e=>{const f=document.querySelector('#objectiveForm');if(!f.reportValidity()){e.preventDefault();return}const fd=new FormData(f),originalId=fd.get('originalId'),subject=f.elements.subject.value,values={subject,code:fd.get('code'),group:fd.get('group'),title:fd.get('title'),category:fd.get('category'),level:fd.get('level')};if(originalId){const custom=data.customObjectives.find(o=>o.id===originalId);if(custom)Object.assign(custom,values);else data.objectiveOverrides[originalId]=values}else{values.id=subject+'-custom-'+Date.now();values.custom=true;data.customObjectives.push(values);data.progress[values.id]={school:false,status:'todo',confidence:0}}save();renderAll();toast(originalId?'Syllabus 항목을 수정했습니다':'Syllabus 항목을 추가했습니다')});
document.querySelector('#archiveObjective').addEventListener('click',()=>{const id=document.querySelector('#objectiveForm').elements.originalId.value;if(id&&confirm('이 항목을 보관할까요? 기존 진도 기록은 유지됩니다.')){data.archivedObjectives.push(id);save();document.querySelector('#objectiveDialog').close();renderAll();toast('항목을 보관했습니다')}});
document.querySelector('#accountButton').addEventListener('click',()=>{if(cloudUser){renderWorkspace();document.querySelector('#workspaceError').textContent='';document.querySelector('#workspaceDialog').showModal()}else{document.querySelector('#authForm').reset();document.querySelector('#authError').textContent='';document.querySelector('#authDialog').showModal()}});
async function authenticate(mode){const form=document.querySelector('#authForm');if(!form.reportValidity())return;const email=form.elements.email.value.trim(),password=form.elements.password.value,errorEl=document.querySelector('#authError');errorEl.textContent='';if(!cloudClient){errorEl.textContent='Supabase에 연결할 수 없습니다.';return}const cfg=window.IB_SUPABASE_CONFIG||{};const result=mode==='signup'?await cloudClient.auth.signUp({email,password,options:{emailRedirectTo:cfg.redirectUrl}}):await cloudClient.auth.signInWithPassword({email,password});if(result.error){errorEl.textContent=result.error.message;return}document.querySelector('#authDialog').close();if(mode==='signup'&&!result.data.session)toast('확인 이메일을 보냈습니다. 이메일 인증 후 로그인하세요.');else toast(mode==='signup'?'계정을 만들었습니다':'로그인했습니다')}
document.querySelector('#signUpButton').addEventListener('click',()=>authenticate('signup'));document.querySelector('#signInButton').addEventListener('click',()=>authenticate('signin'));
document.querySelector('#workspaceSignOut').addEventListener('click',async()=>{if(confirm('모든 기기에서 로그아웃할까요?')){document.querySelector('#workspaceDialog').close();await cloudClient.auth.signOut()}});
document.querySelector('#createWorkspace').addEventListener('click',async()=>{const form=document.querySelector('#workspaceForm'),name=form.elements.workspaceName.value.trim(),errorEl=document.querySelector('#workspaceError');errorEl.textContent='';if(!name){errorEl.textContent='Workspace 이름을 입력하세요.';return}const result=await cloudClient.rpc('create_family_workspace',{workspace_name:name});if(result.error){errorEl.textContent=result.error.message;return}await refreshWorkspace();await loadCloudData();renderWorkspace();toast('가족 Workspace를 만들었습니다')});
document.querySelector('#joinWorkspace').addEventListener('click',async()=>{const form=document.querySelector('#workspaceForm'),code=form.elements.inviteCode.value.trim().toUpperCase(),errorEl=document.querySelector('#workspaceError');errorEl.textContent='';if(code.length!==8){errorEl.textContent='8자리 초대 코드를 입력하세요.';return}const result=await cloudClient.rpc('join_family_workspace',{code});if(result.error){errorEl.textContent=result.error.message;return}await refreshWorkspace();await loadCloudData();renderWorkspace();toast('가족 Workspace에 참여했습니다')});
document.querySelector('#todayLabel').textContent=new Intl.DateTimeFormat('ko-KR',{year:'numeric',month:'long',day:'numeric',weekday:'long'}).format(new Date());
if('serviceWorker'in navigator&&location.protocol.startsWith('http'))navigator.serviceWorker.register('./sw.js');
renderAll();
initCloud();
checkForAppUpdate();
